import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Lock, LockOpen, BatteryChargingFull } from '@mui/icons-material';
import response from './response.json';

interface LockStatus {
  currentState: string;
  batteryLevel: number;
}

interface RecentAccess {
  time: string;
  user: string;
  action: string;
}

interface WidgetData {
  lockStatus: LockStatus;
  recentAccessLog: RecentAccess[];
  authorizedUsersCount: number;
}

export default function Widget() {
  const data = response.data as WidgetData;
  const { lockStatus, recentAccessLog, authorizedUsersCount } = data;

  const lockIcon = lockStatus.currentState === 'Locked' ? <Lock /> : <LockOpen />;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#1E1E1E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Stack direction="row" alignItems="center" spacing={1}>
              {lockIcon}
              <Typography variant="h6" fontWeight={700}>
                {lockStatus.currentState}
              </Typography>
            </Stack>
            <Stack direction="row" alignItems="center" spacing={1} sx={{ mt: 0.5 }}>
              <BatteryChargingFull sx={{ fontSize: 16, color: '#4A90E2' }} />
              <Typography variant="body2" color="text.secondary">
                Battery: {lockStatus.batteryLevel}%
              </Typography>
            </Stack>
          </Box>

          <Box>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Recent Access Log
            </Typography>
            <Stack spacing={1}>
              {recentAccessLog.slice(0, 3).map((log, index) => (
                <Box key={index}>
                  <Typography variant="caption" color="text.secondary">
                    {log.time} - {log.user} - {log.action}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>

          <Box>
            <Stack direction="row" justifyContent="space-between">
              <Typography variant="body2" color="text.secondary">
                Authorized Users
              </Typography>
              <Chip label={authorizedUsersCount} sx={{ bgcolor: '#D0021B', color: '#FFFFFF', fontWeight: 600 }} />
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
